<?php ao_schema_ensure_v1200(); $rows=[]; try{$rows=db()->query('SELECT e.*, l.title, l.domain_name FROM marketplace_escrow e LEFT JOIN marketplace_listings l ON l.id=e.listing_id ORDER BY e.id DESC LIMIT 200')->fetchAll();}catch(Throwable $e){} ?>
<div class="ao-page-head"><div><h2>Marketplace Escrow</h2><p>İş teslimi ve alıcı onayı sonrası ödeme bırakma altyapısı.</p></div></div>
<div class="ao-card"><table class="ao-table"><thead><tr><th>İlan</th><th>Tutar</th><th>Durum</th><th>Sipariş</th><th>Not</th><th>Tarih</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><?= e($r['domain_name'] ?: $r['title']) ?></td><td><?= number_format((float)$r['amount'],2,',','.') ?> <?= e($r['currency']) ?></td><td><?= e($r['status']) ?></td><td>#<?= (int)$r['order_id'] ?></td><td><?= e($r['release_note']) ?></td><td><?= e($r['created_at']) ?></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="6">Escrow kaydı yok. Marketplace satışı sonrası otomatik oluşacak.</td></tr><?php endif; ?></tbody></table></div>
